select MIN(stk.id) id,
       m.code materialCode,
       m.name materialName,
       SUM(IFNULL(stk.qty, 0)) materialQty,
       m.speci materialSpeci,
       m.model materialModel,
       u.unit_name unitName,
       stk.material_id material_id,
       CASE WHEN SUM(IFNULL(stk.qty, 0)) <> 0
            THEN SUM(IFNULL(stk.amt, IFNULL(stk.qty, 0) * IFNULL(stk.unit_price, 0))) / SUM(IFNULL(stk.qty, 0))
            ELSE NULL END unitPrice,
       ROUND(SUM(IFNULL(stk.amt, IFNULL(stk.qty, 0) * IFNULL(stk.unit_price, 0))), 2) materialAmt,
       MAX(w.name) warehouseName,
       MAX(f.factory_name) factoryName,
       MAX(s.name) supplierName
from stk_inventory stk
left join fd_warehouse w on stk.warehouse_id = w.id
left join fd_supplier s on stk.supplier_id = s.id
left join fd_material m on stk.material_id = m.id
left join fd_unit u on u.unit_id = m.unit_id
left join fd_factory f on f.factory_id = m.factory_id
where (stk.del_flag = 0 or stk.del_flag is null)
  and stk.tenant_id = #{tenantId}

 and stk.material_id = #{materialId}
 and stk.warehouse_id = #{warehouseId} 
 and stk.unit_price = #{unitPrice}
 and stk.amt = #{amt}
 and stk.qty = #{qty}
 and stk.batch_no = #{batchNo}
 and stk.batch_number like concat('%', #{batchNumber}, '%')
 and stk.receipt_order_no like concat('%', #{receiptOrderNo}, '%')
 and stk.material_no = #{materialNo}
 and stk.material_date = #{materialDate}
 and stk.warehouse_date = #{warehouseDate}
 and DATE(stk.warehouse_date) >= #{beginDate} 
 and DATE(stk.warehouse_date) <= #{endDate} 
 and w.name like concat('%', #{warehouseName}, '%')
 and (m.name like concat('%', #{materialName}, '%') or m.code like concat('%', #{materialName}, '%') or m.referred_name like concat('%', #{materialName}, '%'))
 and m.speci like concat('%', #{materialSpeci}, '%')
 and m.model like concat('%', #{materialModel}, '%')
 and stk.supplier_id = #{supplierId} 


         and m.is_billing = '1' 
         and (m.is_billing in ('0','2') or m.is_billing is null or m.is_billing = '') 


 and m.storeroom_id = #{warehouseCategoryId}
GROUP BY stk.material_id, stk.warehouse_id, m.code, m.name, m.speci, m.model, u.unit_name
order by m.code, MAX(w.name)

