qty = #{qty}, material_id = #{materialId}, material_name = #{snapMaterialName}, material_speci = #{snapMaterialSpeci}, material_model = #{snapMaterialModel}, material_factory_id = #{snapMaterialFactoryId}, warehouse_id = #{warehouseId}, unit_price = #{unitPrice}, amt = #{amt}, batch_no = #{batchNo}, batch_id = #{batchId}, material_no = #{materialNo}, material_date = #{materialDate}, warehouse_date = #{warehouseDate}, supplier_id = #{supplierId}, factory_id = #{factoryId}, begin_time = #{beginTime}, end_time = #{endTime}, receipt_order_no = #{receiptOrderNo}, kc_no = #{kcNo}, batch_number = #{batchNumber}, tenant_id = #{tenantId}, settlement_type = #{settlementType}, main_barcode = #{mainBarcode}, sub_barcode = #{subBarcode}, del_flag = #{delFlag},
