update stk_inventory
set qty = IFNULL(qty, 0) - #{delta},
    amt = IFNULL(unit_price, 0) * qty,
    update_time = now(),
    update_by = #{updateBy}
where id = #{id}
  and tenant_id = #{scopedTenantId}
  and (del_flag = 0 or del_flag is null)
  and IFNULL(qty, 0) >= #{delta}

