select stk.id, IFNULL(m.code, '') materialCode, IFNULL(m.name, '') materialName, IFNULL(m.speci, '') materialSpeci, IFNULL(m.model, '') materialModel, IFNULL(u.unit_name, '') unitName, IFNULL(stk.unit_price, 0) unitPrice, IFNULL(w.name, '') warehouseName, IFNULL(stk.batch_no, '') batchNo, stk.begin_time produceDate, stk.end_time expiryDate, DATEDIFF(stk.end_time, CURDATE()) daysRemaining, IFNULL(stk.qty, 0) qty, IFNULL(f.factory_name, '') factoryName, IFNULL(s.name, '') supplierName from stk_inventory stk left join fd_warehouse w on stk.warehouse_id = w.id left join fd_supplier s on stk.supplier_id = s.id left join fd_material m on stk.material_id = m.id left join fd_unit u on u.unit_id = m.unit_id left join fd_factory f on f.factory_id = m.factory_id where stk.qty > 0 and stk.end_time IS NOT NULL and (m.id IS NULL OR m.del_flag IS NULL OR m.del_flag != 1) and (m.id IS NULL OR m.is_use IS NULL OR m.is_use = '' OR m.is_use != '2') and stk.tenant_id = #{tenantId}
and DATEDIFF(stk.end_time, CURDATE()) <= #{daysToExpiry} and DATEDIFF(stk.end_time, CURDATE()) >= -#{daysToExpiry}
and DATEDIFF(stk.end_time, CURDATE()) <= 90 and DATEDIFF(stk.end_time, CURDATE()) >= -90
and stk.warehouse_id = #{warehouseId}
and (IFNULL(m.name, '') like concat('%', #{materialName}, '%') or IFNULL(m.code, '') like concat('%', #{materialName}, '%'))
and stk.supplier_id = #{supplierId}
order by stk.end_time asc, stk.id asc


